// ============================================================
// Sydney Bot — Core Processing Pipeline (n8n Code Node)
// ============================================================

// --- Input ---
const webhookData = $('Webhook').first().json;
const answerText = webhookData.body?.text || webhookData.body?.answerText || '';
if (!answerText) {
  return [{ json: { error: 'No text provided. Send JSON with { "text": "..." }' } }];
}

const dbDefenses = $('Fetch DB Defenses').first().json;
// n8n HTTP Request returns array at top level or nested
const defenseList = Array.isArray(dbDefenses) ? dbDefenses : (dbDefenses.data || []);

// --- Ordinal helpers ---
const ORDINALS = [
  'First', 'Second', 'Third', 'Fourth', 'Fifth', 'Sixth', 'Seventh', 'Eighth',
  'Ninth', 'Tenth', 'Eleventh', 'Twelfth', 'Thirteenth', 'Fourteenth', 'Fifteenth',
  'Sixteenth', 'Seventeenth', 'Eighteenth', 'Nineteenth', 'Twentieth',
  'Twenty-First', 'Twenty-Second', 'Twenty-Third', 'Twenty-Fourth', 'Twenty-Fifth',
  'Twenty-Sixth', 'Twenty-Seventh', 'Twenty-Eighth', 'Twenty-Ninth', 'Thirtieth',
  'Thirty-First', 'Thirty-Second', 'Thirty-Third', 'Thirty-Fourth', 'Thirty-Fifth',
  'Thirty-Sixth', 'Thirty-Seventh', 'Thirty-Eighth', 'Thirty-Ninth', 'Fortieth',
  'Forty-First', 'Forty-Second', 'Forty-Third', 'Forty-Fourth', 'Forty-Fifth',
  'Forty-Sixth', 'Forty-Seventh', 'Forty-Eighth', 'Forty-Ninth', 'Fiftieth',
];

function ordinalToNumber(ordinal) {
  const idx = ORDINALS.findIndex(o => o.toLowerCase() === ordinal.toLowerCase());
  return idx >= 0 ? idx + 1 : null;
}

function numberToOrdinal(num) {
  return ORDINALS[num - 1] || `${num}th`;
}

// --- Step 1: Parse case metadata ---
function parseCaseMetadata(text) {
  text = text.replace(/[\u2018\u2019\u201A\u201B]/g, "'").replace(/[\u201C\u201D\u201E\u201F]/g, '"');

  let plaintiffName = null;
  const plaintiffPatterns = [
    /\n([A-Z][A-Z\s.,&'"\-()]+?)\s*,?\s*\n\s*Plaintiff/,
    /FLORIDA\s*\n+([\s\S]*?)\s*,?\s*\n\s*Plaintiff/i,
  ];
  for (const pat of plaintiffPatterns) {
    const m = text.match(pat);
    if (m) {
      plaintiffName = m[1].trim().replace(/\s+/g, ' ').replace(/\s*,\s*$/, '');
      plaintiffName = plaintiffName
        .replace(/^.*?FLORIDA\s*/i, '')
        .replace(/^(?:COUNTY\s+CIVIL\s+DIVISION|CIVIL\s+DIVISION)\s*/i, '')
        .trim();
      if (plaintiffName.length > 3) break;
    }
  }

  let defendantName = null;
  const defendantPatterns = [
    /[Vv][Ss]?\.\s*(?:CASE[^\n]*\n)?\s*\n*([\s\S]*?)\s*,?\s*\n\s*Defendant/i,
    /\nvs?\.\s*\n([\s\S]*?)\s*,?\s*\n\s*Defendant/i,
  ];
  for (const pat of defendantPatterns) {
    const m = text.match(pat);
    if (m) {
      defendantName = m[1].trim().replace(/\s+/g, ' ').replace(/\s*,\s*$/, '');
      if (defendantName.length > 3) break;
    }
  }

  let caseNumber = null;
  const caseMatch = text.match(/CASE\s*NO\.?\s*:?\s*(\d{4}[A-Z]{2}\d+)/i);
  if (caseMatch) caseNumber = caseMatch[1];

  let court = null;
  const courtMatch = text.match(/IN\s+(?:THE\s+)?(?:CIRCUIT|COUNTY)\s+COURT\s+OF\s+THE[\s\S]*?COUNTY,?\s*\n?\s*FLORIDA/i);
  if (courtMatch) court = courtMatch[0].replace(/\s+/g, ' ').trim();

  return { plaintiffName, defendantName, caseNumber, court };
}

// --- Step 2: Split affirmative defenses ---
function splitAffirmativeDefenses(text) {
  text = text.replace(/[\u2018\u2019\u201A\u201B]/g, "'").replace(/[\u201C\u201D\u201E\u201F]/g, '"');

  const affDefStart = text.search(/AFFIRMATIVE\s+DEFENSES/i);
  if (affDefStart === -1) return [];
  const affText = text.substring(affDefStart);

  const defensePattern = /(?:^|\n)\s*(?:(\w+(?:-\w+)?)\s+AFFIRMATIVE\s+DEFENSE|(\d+)\.\s+(?:AFFIRMATIVE\s+DEFENSE|As\s+(?:a\s+)?(?:its?\s+)?(?:\w+(?:-\w+)?)\s+[Aa]ffirmative\s+[Dd]efense))/gi;

  const positions = [];
  let match;
  while ((match = defensePattern.exec(affText)) !== null) {
    const ordinalWord = match[1];
    const numberStr = match[2];
    if (ordinalWord && !ordinalToNumber(ordinalWord)) continue;

    let defenseNumber;
    if (ordinalWord) {
      defenseNumber = ordinalToNumber(ordinalWord);
    } else {
      defenseNumber = parseInt(numberStr, 10);
    }

    const actualIndex = match.index + (match[0].length - match[0].trimStart().length);
    positions.push({ index: actualIndex, defenseNumber, matchText: match[0].trim() });
  }

  const seenNumbers = new Set();
  const uniquePositions = positions.filter(p => {
    if (seenNumbers.has(p.defenseNumber)) return false;
    seenNumbers.add(p.defenseNumber);
    return true;
  });

  const defenses = [];
  for (let i = 0; i < uniquePositions.length; i++) {
    const start = uniquePositions[i].index;
    const end = i + 1 < uniquePositions.length ? uniquePositions[i + 1].index : affText.length;
    defenses.push({
      defenseNumber: uniquePositions[i].defenseNumber,
      ordinal: numberToOrdinal(uniquePositions[i].defenseNumber),
      rawText: affText.substring(start, end).trim(),
    });
  }
  return defenses;
}

// --- Step 3: Classify defense ---
function classifyDefense(defenseText) {
  const text = defenseText.toLowerCase();

  const citesSpecificProvisions = (
    /deductible/i.test(text) ||
    /limits of liability/i.test(text) ||
    /mortgagee/i.test(text) ||
    /payment method/i.test(text) ||
    /certain provisions/i.test(text)
  );
  const isGenericPolicyDefense = (
    /all terms,?\s*conditions/i.test(text) ||
    /entire policy/i.test(text) ||
    /all conditions of the policy/i.test(text)
  );

  const isQuotingPolicyExclusions = (
    /section i/i.test(text) &&
    (/losses not insured/i.test(text) || /losses insured/i.test(text)) &&
    /we will not pay/i.test(text)
  );
  const mentionsWearAndTear = /wear.{0,5}tear/i.test(text) || /deterioration/i.test(text);
  const isDefendantArguingWearTear = mentionsWearAndTear && (
    /observed evidence of wear/i.test(text) ||
    /as a result of.*(?:wear|deterioration|mechanical)/i.test(text) ||
    /consistent with.*(?:wear|deterioration)/i.test(text) ||
    /damage.*caused by.*(?:wear|tear|deterioration)/i.test(text)
  );

  const categorySignals = [
    { category: 'failure to state cause of action', patterns: ['failure to state', 'cause of action', 'fails to state'] },
    { category: 'Duties after Loss', patterns: ['duties after loss', 'post-loss duties', 'post loss duties', 'duty after loss', 'failed to comply with', 'conditions precedent', 'failed to notify', 'failed to give', 'sworn proof of loss', 'material breaches of the policy'] },
    { category: 'wear and tear', patterns: ['wear and tear', 'deterioration', 'gradual deterioration'] },
    { category: 'preexisting damages', patterns: ['pre-existing', 'preexisting', 'prior damage', 'existing damage', 'pre existing'] },
    { category: 'SET OFF', patterns: ['set off', 'setoff', 'set-off', 'offset'] },
    { category: 'fraud and misrepresentation', patterns: ['fraud', 'misrepresentation', 'material misrepresentation', 'fraudulent'] },
    { category: 'fraud and concealment', patterns: ['concealment', 'conceal'] },
    { category: 'No Standing', patterns: ['standing', 'lack of standing', 'no standing'] },
    { category: 'No further Coverage', patterns: ['no further coverage', 'no coverage', 'coverage does not extend'] },
    { category: 'Loss Settlement provision', patterns: ['loss settlement', 'replacement cost', 'actual cash value settlement'] },
    { category: 'failure to protect', patterns: ['failure to protect', 'failed to protect', 'protect the property', 'mitigate'] },
    { category: 'ACV only', patterns: ['actual cash value', 'acv', 'acv only', 'limited to the actual cash value'] },
    { category: 'entire policy', patterns: ['entire policy', 'all conditions of the policy', 'all terms, conditions, exclusions'] },
    { category: 'matching costs', patterns: ['matching', 'match in quality', 'match in color', 'undamaged property'] },
    { category: 'ordinance and law', patterns: ['ordinance', 'building code', 'ordinance or law', 'code upgrade'] },
    { category: 'rain', patterns: ['rain', 'rainfall', 'rainwater'] },
    { category: 'Building, shrinking settling', patterns: ['settling', 'shrinking', 'bulging', 'cracking', 'expansion'] },
    { category: 'roof surfacing schedule', patterns: ['roof surfacing', 'roof schedule', 'roof payment schedule'] },
    { category: 'late reporting', patterns: ['late report', 'late notice', 'untimely notice', 'timely report'] },
    { category: 'post-loss duties', patterns: ['post-loss', 'post loss', 'sworn statement', 'examination under oath'] },
    { category: 'Notice of Intent to Litigate', patterns: ['notice of intent', 'intent to litigate', 'civil remedy'] },
    { category: 'suit against us', patterns: ['suit against us', 'legal action against', 'limitations period'] },
    { category: 'Exterior Paint', patterns: ['exterior paint', 'paint', 'cosmetic'] },
    { category: 'excessive pricing', patterns: ['excessive', 'inflated', 'unreasonable pricing', 'excessive pricing'] },
    { category: 'Endorsement HO 06 41', patterns: ['endorsement', 'ho 06 41', 'ho-06-41'] },
    { category: 'no peril created opening', patterns: ['opening', 'peril created opening', 'no opening'] },
    { category: 'failure to provide documents', patterns: ['failure to provide', 'documents', 'records'] },
    { category: 'full payment of actual cash value', patterns: ['full payment', 'paid in full', 'full acv'] },
    { category: 'No notice of Disputed Actual Cash Value', patterns: ['disputed actual cash', 'notice of disputed'] },
    { category: 'Enclosure and other Property excluded by Hurricane loss', patterns: ['enclosure', 'hurricane', 'screen enclosure'] },
    { category: 'no covered ensuing losses', patterns: ['ensuing loss', 'ensuing damage', 'no covered'] },
    { category: 'duplicative', patterns: ['duplicative', 'same as first', 'same as 1st', 'previously stated', 'realleges and incorporates', 're-alleges and incorporates all prior'] },
    { category: 'loss settlement- 1% matching', patterns: ['1%', 'one percent', 'matching limit', '1 percent'] },
    { category: 'DEFAULT', patterns: [] },
  ];

  const scores = [];
  for (const signal of categorySignals) {
    let score = 0;
    for (const pattern of signal.patterns) {
      if (text.includes(pattern)) score++;
    }
    if (score > 0) scores.push({ category: signal.category, score });
  }
  scores.sort((a, b) => b.score - a.score);

  let result = scores.length > 0
    ? { category: scores[0].category, confidence: scores[0].score / Math.max(scores[0].score, 2), allMatches: scores }
    : { category: 'UNMATCHED', confidence: 0, allMatches: [] };

  if (result.category === 'wear and tear' && isQuotingPolicyExclusions && !isDefendantArguingWearTear) {
    result.category = 'DEFAULT';
    result.confidence = 0.8;
  }
  if (citesSpecificProvisions && !isGenericPolicyDefense) {
    result.category = 'No further Coverage';
    result.confidence = 0.9;
  }
  if (result.category === 'entire policy' && citesSpecificProvisions) {
    result.category = 'No further Coverage';
    result.confidence = 0.9;
  }

  return result;
}

// --- Step 4: Match to database ---
function matchToDatabase(classification, dbDefs) {
  const catName = classification.category.toLowerCase();
  const matches = dbDefs.filter(d => {
    const dbCatName = (d.categories?.name || '').toLowerCase();
    if (dbCatName === catName) return true;
    if (dbCatName.includes(catName) || catName.includes(dbCatName)) return true;
    if (d.keywords && d.keywords.length > 0) {
      const catWords = catName.split(/[\s,/&-]+/).filter(w => w.length > 2);
      const overlap = d.keywords.filter(kw => catWords.includes(kw.toLowerCase()));
      if (overlap.length >= 2) return true;
    }
    return false;
  });
  if (matches.length > 0) {
    return { matched: true, defense: matches[0], confidence: classification.confidence };
  }
  return { matched: false, defense: null, confidence: 0 };
}

// --- Step 5: Personalize defense text ---
function personalizeDefenseText(defText, defenseNumber, meta) {
  let result = defText;
  const ordinalPattern = /As to Defendant[\u2019']s\s+(\w+(?:-\w+)?)\s+Affirmative\s+Defense/gi;
  const newOrdinal = numberToOrdinal(defenseNumber);
  result = result.replace(ordinalPattern, `As to Defendant's ${newOrdinal} Affirmative Defense`);

  const altPattern = /As to (\w+(?:-\w+)?)\s+Affirmative\s+Defense/i;
  if (!result.match(/As to Defendant/i)) {
    result = result.replace(altPattern, `As to Defendant's ${newOrdinal} Affirmative Defense`);
  }

  if (meta.coverageLetterDate) {
    result = result.replace(
      /Coverage letter dated\s+\w+\s+\d{1,2},\s*\d{4}/gi,
      `Coverage letter dated ${meta.coverageLetterDate}`
    );
  }
  return result;
}

// --- Step 6: Assemble reply ---
function assembleReply(meta, matchedDefenses) {
  const parts = [];
  parts.push(meta.court || 'IN THE CIRCUIT COURT OF THE _____ JUDICIAL CIRCUIT');
  parts.push('');
  parts.push(meta.plaintiffName || '[PLAINTIFF NAME]');
  parts.push(`\t\t\t\t\tCASE NO.: ${meta.caseNumber || '[CASE NUMBER]'}`);
  parts.push('\tPlaintiffs,');
  parts.push('v.');
  parts.push(meta.defendantName || '[DEFENDANT NAME]');
  parts.push('\tDefendant.');
  parts.push('______________________________________/');
  parts.push('');
  parts.push("PLAINTIFFS' MOTION TO STRIKE AND REPLY/AVOIDANCE TO DEFENDANT'S AFFIRMATIVE DEFENSES");
  parts.push('');
  const plaintiffRef = meta.plaintiffName || '[PLAINTIFF NAME]';
  parts.push(
    `Plaintiffs, ${plaintiffRef}, by and through undersigned attorneys, and pursuant to ` +
    `Florida Rule of Civil Procedure 1.100, hereby files this Reply/Avoidance of Defendant's ` +
    `Answer and Affirmative Defenses and Motion to Strike Defendant's Affirmative Defenses as follows:`
  );
  parts.push('');
  parts.push(
    `As memorialized in B & S Associates, Inc. v. Indem. Cas. & Prop., Ltd., 641 So. 2d 436, 437 ` +
    `(Fla. 4th DCA 1994)`
  );
  parts.push('');
  parts.push(
    `[I]t would appear that all risk insurance arose for the very purpose of protecting the insured ` +
    `in those cases where difficulties of logical explanation or some mystery surround the loss or ` +
    `damage to property. It would seem to be inconsistent with the broad protective purposes of ` +
    `"all-risks" insurance to impose on the insured, as Insurer would have us do, the burden of ` +
    `proving precise cause of loss or damage.`
  );
  parts.push('');
  parts.push('citing Morrison Grain Co. v. Utica Mutual Insurance Co., 632 F.2d 424 (5th Cir.1980).');
  parts.push('');

  for (const item of matchedDefenses) {
    if (item.matched && item.responseText) {
      parts.push(item.responseText);
    } else {
      parts.push(`[UNMATCHED - NEEDS LAWYER REVIEW] As to Defendant's ${item.ordinal} Affirmative Defense:`);
      parts.push(`Original defense text: "${item.rawText.substring(0, 200)}..."`);
      parts.push(`Suggested category: ${item.suggestedCategory || 'None'}`);
    }
    parts.push('');
  }
  return parts.join('\n');
}

// ============================================================
// MAIN PIPELINE
// ============================================================

const caseMetadata = parseCaseMetadata(answerText);
const incomingDefenses = splitAffirmativeDefenses(answerText);

const results = [];
const usedCategories = new Set();
const noDedup = ['DEFAULT', 'UNMATCHED', 'No further Coverage', 'SET OFF'];

for (const incoming of incomingDefenses) {
  const classification = classifyDefense(incoming.rawText);

  if (usedCategories.has(classification.category) && !noDedup.includes(classification.category)) {
    classification.originalCategory = classification.category;
    classification.category = 'DEFAULT';
    classification.confidence = 0.7;
  }

  const match = matchToDatabase(classification, defenseList);
  usedCategories.add(classification.originalCategory || classification.category);

  let responseText = null;
  if (match.matched) {
    responseText = personalizeDefenseText(
      match.defense.defense_text,
      incoming.defenseNumber,
      caseMetadata
    );
  }

  results.push({
    defenseNumber: incoming.defenseNumber,
    ordinal: incoming.ordinal,
    rawText: incoming.rawText,
    matched: match.matched,
    matchedCategory: match.matched ? match.defense.categories?.name : null,
    suggestedCategory: classification.category,
    confidence: classification.confidence,
    responseText,
    flagged: !match.matched,
  });
}

const reply = assembleReply(caseMetadata, results);

const matched = results.filter(r => r.matched).length;
const flagged = results.filter(r => r.flagged).length;

return [{
  json: {
    caseMetadata,
    summary: {
      totalDefenses: results.length,
      matched,
      flagged,
    },
    results,
    reply,
  }
}];
